const POOL_3 = [
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Dans un lac, un nénuphar double de surface chaque jour. S'il lui faut 30 jours pour recouvrir tout le lac, combien de jours lui a-t-il fallu pour n'en recouvrir que la moitié ?", hint: "Ne fais pas de division par deux sur le temps.", answer: "29 jours", text_en: "Lily pad doubles daily. 30 days to cover lake. Half coverage after how many days?", hint_en: "Don't halve the time.", answer_en: "29 days", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si 5 machines prennent 5 minutes pour fabriquer 5 objets, combien de temps faut-il à 100 machines pour fabriquer 100 objets ?", hint: "Chaque machine travaille en parallèle.", answer: "5 minutes", text_en: "5 machines make 5 widgets in 5 minutes. How long for 100 machines to make 100?", hint_en: "Each machine works in parallel.", answer_en: "5 minutes", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le seul nombre qui, lorsqu'on le divise par lui-même, donne son double ?", hint: "Il doit être plus petit que 1.", answer: "0.5 (0.5 ÷ 0.5 = 1 = 0.5 × 2)", text_en: "Which number divided by itself equals its double?", hint_en: "It must be less than 1.", answer_en: "0.5 (0.5÷0.5=1=0.5×2)", category_en: "Mathematics" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si tu retournes un nombre à 2 chiffres, tu obtiens un nombre 63 plus grand. La somme des deux chiffres est 9. Quel est le nombre ?", hint: "Pose les équations avec a et b.", answer: "18 (81-18=63, 1+8=9)", text_en: "Reversing a 2-digit number gives one 63 larger. Digit sum is 9. What's the number?", hint_en: "Set up equations with a and b.", answer_en: "18 (81-18=63, 1+8=9)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un fermier a 3 types d'animaux : des poulets, des vaches et des moutons. Il a 30 animaux en tout, 74 pattes et 24 têtes animales. Combien de chaque ?", hint: "Pose un système d'équations.", answer: "10 poulets (2 pattes), 10 vaches (4 pattes), 10 moutons (4 pattes) — à ajuster selon les pattes", text_en: "Farmer has chickens, cows, sheep: 30 animals, 74 legs, 24 heads. How many of each?", hint_en: "Set up a system of equations.", answer_en: "Solve the system: 2c+4v+4s=74, c+v+s=30", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la somme des 100 premiers nombres naturels ?", hint: "Gauss a résolu ça à 9 ans. Pense aux paires.", answer: "5050 (100×101÷2)", text_en: "What is the sum of the first 100 natural numbers?", hint_en: "Gauss solved this at age 9. Think pairs.", answer_en: "5050 (100×101÷2)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu peux lire 1 livre en 10 jours, combien de livres peux-tu lire en 100 jours ?", hint: "C'est simple mais vérifie les unités.", answer: "10 livres", text_en: "If you read 1 book in 10 days, how many in 100 days?", hint_en: "Simple but check units.", answer_en: "10 books", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Un nombre est 5 fois la somme de ses chiffres. Quel est-il ?", hint: "Soit n = 10a+b et n = 5(a+b).", answer: "45 (4+5=9, 9×5=45)", text_en: "A number equals 5 times its digit sum. What is it?", hint_en: "Let n=10a+b and n=5(a+b).", answer_en: "45 (4+5=9, 9×5=45)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Il y a 3 boîtes : une avec des pommes, une avec des oranges, et une avec un mélange. Toutes les étiquettes sont fausses. En prenant 1 seul fruit d'une seule boîte, comment trouves-tu tout ?", hint: "Prends un fruit de la boîte 'mélange'.", answer: "Pioche dans 'Mélange' — si tu prends une pomme, c'est la boîte 'Pommes'. Déduis les autres par élimination.", text_en: "3 mislabeled boxes: apples, oranges, mix. One fruit from one box. How to identify all?", hint_en: "Pick from the 'mix' box.", answer_en: "Pick from 'mix' — whatever you get names that box. Deduce others by elimination.", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si 6 chats attrapent 6 souris en 6 minutes, combien de chats attrapent 100 souris en 100 minutes ?", hint: "Trouve le taux par chat.", answer: "6 chats (même ratio)", text_en: "6 cats catch 6 mice in 6 minutes. How many cats to catch 100 mice in 100 minutes?", hint_en: "Find rate per cat.", answer_en: "6 cats (same ratio)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Tu as 8 balles identiques sauf une qui est plus lourde. Avec une balance à plateaux sans poids, quel est le minimum de pesées pour trouver la balle lourde ?", hint: "Pense à diviser en 3 groupes.", answer: "2 pesées", text_en: "8 identical balls, one heavier. Minimum weighings on a balance scale to find it?", hint_en: "Think divide into 3 groups.", answer_en: "2 weighings", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le dernier chiffre de 7^100 ?", hint: "Cherche le cycle des puissances de 7.", answer: "1 (cycle de 7: 7,9,3,1 — 100÷4=25 reste 0, donc le 4ème = 1)", text_en: "What is the last digit of 7^100?", hint_en: "Find the cycle of powers of 7.", answer_en: "1 (cycle 7,9,3,1 — 100÷4=0 remainder, so 4th = 1)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un escargot est au fond d'un puits de 20 mètres. Chaque jour il monte de 5 mètres et chaque nuit il redescend de 4 mètres. En combien de jours sort-il ?", hint: "Le dernier jour il monte 5 d'un coup.", answer: "16 jours", text_en: "Snail at bottom of 20m well. Climbs 5m by day, slips 4m at night. How many days to escape?", hint_en: "Last day it climbs 5 at once.", answer_en: "16 days", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la somme de tous les angles d'un pentagone ?", hint: "Utilise la formule (n-2)×180.", answer: "540°", text_en: "What is the sum of all angles in a pentagon?", hint_en: "Use formula (n-2)×180.", answer_en: "540°", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Tu as 12 balles, une est de poids différent. Tu ne sais pas si elle est plus lourde ou plus légère. Minimum de pesées pour la trouver ET savoir si elle est lourde ou légère ?", hint: "C'est un problème classique de logique.", answer: "3 pesées", text_en: "12 balls, one odd weight (don't know heavier/lighter). Min weighings to find it AND know if heavier/lighter?", hint_en: "Classic logic problem.", answer_en: "3 weighings", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si le périmètre d'un carré est 36 cm, quelle est son aire ?", hint: "Périmètre = 4×côté.", answer: "81 cm²", text_en: "If a square has perimeter 36cm, what is its area?", hint_en: "Perimeter = 4 × side.", answer_en: "81 cm²", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "4 hommes doivent traverser un pont de nuit. Ils ont une seule lampe et ne peuvent traverser qu'à 2 à la fois. Leurs vitesses: 1, 2, 5, 10 min. La lampe doit revenir. Temps minimum ?", hint: "Le plus rapide fait des allers-retours.", answer: "17 minutes", text_en: "4 men cross a bridge at night with one torch, 2 at a time. Times: 1,2,5,10 min. Minimum time?", hint_en: "Fastest person shuttles.", answer_en: "17 minutes", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Combien de zéros y a-t-il à la fin de 100! (factorielle de 100) ?", hint: "Compte les paires de 2 et 5.", answer: "24 (floor(100/5)+floor(100/25)=20+4)", text_en: "How many trailing zeros in 100! (100 factorial)?", hint_en: "Count pairs of 2 and 5.", answer_en: "24 (⌊100/5⌋+⌊100/25⌋=20+4)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Trois robinets remplissent un bassin en 6h, 4h et 3h respectivement. Combien de temps mettront-ils ensemble ?", hint: "Additionne les débits.", answer: "4/3 h = 1h20min (1/6+1/4+1/3=3/4 par heure → 4/3h)", text_en: "Three pipes fill a tank in 6h, 4h, 3h. Time together?", hint_en: "Add the flow rates.", answer_en: "4/3 h ≈ 1h20min", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le nombre de diagonales d'un hexagone ?", hint: "Formule: n(n-3)/2.", answer: "9 diagonales", text_en: "How many diagonals does a hexagon have?", hint_en: "Formula: n(n-3)/2.", answer_en: "9 diagonals", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu empiles des cubes 3×3×3 pour former un grand cube 6×6×6, combien de petits cubes sont complètement à l'intérieur ?", hint: "Soustrais les couches extérieures.", answer: "8 (2×2×2 au centre)", text_en: "Stack 3×3×3 small cubes to form 6×6×6. How many are completely inside?", hint_en: "Subtract outer layers.", answer_en: "8 (2×2×2 at center)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Résous: si x + 1/x = 3, alors x² + 1/x² = ?", hint: "Élève au carré x + 1/x.", answer: "7 ((x+1/x)²=x²+2+1/x²=9, donc x²+1/x²=7)", text_en: "If x + 1/x = 3, what is x² + 1/x²?", hint_en: "Square both sides of x+1/x.", answer_en: "7 ((x+1/x)²=9=x²+2+1/x², so x²+1/x²=7)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un train de 200m arrive dans une gare à 60km/h. Il y a un tunnel de 1km. Combien de temps le train reste-t-il dans le tunnel ?", hint: "Distance totale = longueur tunnel + longueur train.", answer: "72 secondes (1200m ÷ 16.67m/s ≈ 72s)", text_en: "200m train enters 1km tunnel at 60km/h. How long is train fully in tunnel?", hint_en: "Total distance = tunnel + train length.", answer_en: "72 seconds (1200m ÷ 16.67m/s)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Un rectangle a un périmètre de 34 cm. Sa longueur est 3 fois sa largeur. Quelle est son aire ?", hint: "2(L+l)=34 et L=3l.", answer: "60.75 cm² (l=4.25, L=12.75)", text_en: "Rectangle perimeter 34cm. Length is 3× width. Area?", hint_en: "2(L+w)=34 and L=3w.", answer_en: "60.75 cm² (w=4.25, L=12.75)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Tu as 3 seaux de 3L, 5L et 8L. Le seau de 8L est plein. Comment obtenir exactement 4L dans le seau de 5L ?", hint: "Fais des transferts successifs.", answer: "Verse 8→5 (5 plein, 3 dans 8). Verse 5→3 (3 plein, 2 dans 5). Verse 3→8. Verse 5→3 (2 dans 3). Verse 8→5 (5 plein). Verse 5→3 (4 reste dans 5).", text_en: "3L, 5L, 8L buckets. 8L full. Get exactly 4L in 5L?", hint_en: "Make successive transfers.", answer_en: "8→5, 5→3, 3→8, 5→3, 8→5, 5→3: 4L left in 5L", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le PGCD de 120 et 45 ?", hint: "Utilise l'algorithme d'Euclide.", answer: "15 (120=2×45+30, 45=1×30+15, 30=2×15)", text_en: "What is the GCD of 120 and 45?", hint_en: "Use Euclid's algorithm.", answer_en: "15 (120=2×45+30, 45=1×30+15, 30=2×15)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Combien de rectangles (incluant les carrés) y a-t-il dans une grille 4×4 ?", hint: "Choisir 2 lignes parmi 5 et 2 colonnes parmi 5.", answer: "100 (C(5,2)×C(5,2)=10×10)", text_en: "How many rectangles (including squares) in a 4×4 grid?", hint_en: "Choose 2 from 5 lines and 2 from 5 columns.", answer_en: "100 (C(5,2)×C(5,2)=10×10)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si 2^10 = 1024, quelle est la valeur approximative de 2^20 ?", hint: "2^20 = (2^10)².", answer: "1 048 576 ≈ 1 million", text_en: "If 2^10=1024, approximately what is 2^20?", hint_en: "2^20=(2^10)².", answer_en: "1,048,576 ≈ 1 million", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "5 personnes veulent partager 3 pizzas équitablement. Quelle fraction chacune reçoit-elle ?", hint: "Divise le total par le nombre de personnes.", answer: "3/5 de pizza chacune", text_en: "5 people share 3 pizzas equally. What fraction does each get?", hint_en: "Divide total by people.", answer_en: "3/5 of a pizza each", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel nombre naturel, multiplié par lui-même, donne un résultat qui se termine par ...25 ?", hint: "Pense aux carrés qui finissent par 25.", answer: "Tout nombre se terminant par 5 (ex: 5²=25, 15²=225, 25²=625)", text_en: "What natural number multiplied by itself ends in ...25?", hint_en: "Think squares ending in 25.", answer_en: "Any number ending in 5 (5²=25, 15²=225, 25²=625)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Dans une ville il y a 2 types de personnes : les véridiques (toujours vrais) et les menteurs (toujours faux). Tu rencontres A et B. A dit 'B est un menteur'. B dit 'A et moi sommes du même type'. Qui est quoi ?", hint: "Teste les deux hypothèses.", answer: "A est véridique, B est menteur", text_en: "Truth-tellers and liars. A says 'B is a liar.' B says 'A and I are same type.' Who is who?", hint_en: "Test both hypotheses.", answer_en: "A is truth-teller, B is liar", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la valeur de √(2+√(2+√(2+...))) à l'infini ?", hint: "Pose x = √(2+x) et résous.", answer: "2 (x²=2+x → x²-x-2=0 → x=2)", text_en: "What is √(2+√(2+√(2+...))) to infinity?", hint_en: "Let x=√(2+x) and solve.", answer_en: "2 (x²=2+x → x=2)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un marchand gagne 20% sur le prix d'achat. Si le prix de vente est 120 FCFA, quel est le prix d'achat ?", hint: "Prix vente = Prix achat × 1.2.", answer: "100 FCFA", text_en: "Merchant gains 20% on cost. Selling price is 120. Cost price?", hint_en: "Selling price = cost × 1.2.", answer_en: "100", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si tu investis 1000 FCFA à 10% d'intérêts composés par an, combien as-tu après 3 ans ?", hint: "A = P(1+r)^n.", answer: "1331 FCFA (1000×1.1³)", text_en: "Invest 1000 at 10% compound interest/year. Amount after 3 years?", hint_en: "A=P(1+r)^n.", answer_en: "1331 (1000×1.1³)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Quelle est la prochaine valeur : 1, 1, 2, 3, 5, 8, 13, 21, ?", hint: "Suite de Fibonacci.", answer: "34", text_en: "Next value: 1, 1, 2, 3, 5, 8, 13, 21, ?", hint_en: "Fibonacci sequence.", answer_en: "34", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Un triangle rectangle a des cathètes de 6 et 8. Quelle est l'hypoténuse ?", hint: "Théorème de Pythagore.", answer: "10 (6²+8²=100=10²)", text_en: "Right triangle with legs 6 and 8. Hypotenuse?", hint_en: "Pythagorean theorem.", answer_en: "10 (6²+8²=100=10²)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "2, 6, 12, 20, 30, 42... Quelle est la règle et le prochain terme ?", hint: "Regarde les différences.", answer: "56 (n(n+1) : 1×2, 2×3, 3×4... 7×8=56)", text_en: "2, 6, 12, 20, 30, 42... Rule and next term?", hint_en: "Look at the differences.", answer_en: "56 (n(n+1): 7×8=56)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si un cercle a un rayon de 7 cm, quelle est son aire ? (π≈3.14)", hint: "Aire = π×r².", answer: "153.86 cm²", text_en: "Circle with radius 7cm. Area? (π≈3.14)", hint_en: "Area=π×r².", answer_en: "153.86 cm²", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Une boutique fait une remise de 30% puis encore 20%. Quelle est la remise totale ?", hint: "Ce n'est pas 50%.", answer: "44% (0.7×0.8=0.56, remise=44%)", text_en: "A shop gives 30% off then 20% off. Total discount?", hint_en: "It's not 50%.", answer_en: "44% (0.7×0.8=0.56, discount=44%)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la valeur de i² (où i est le nombre imaginaire) ?", hint: "Définition de l'imaginaire.", answer: "-1", text_en: "What is i² (where i is the imaginary unit)?", hint_en: "Definition of imaginary.", answer_en: "-1", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un village a exactement autant d'hommes que de femmes. Chaque homme a épousé exactement une femme. 1/3 des hommes ont les cheveux roux. Les femmes aux cheveux roux ont un mari aux cheveux roux. Quel % des femmes à cheveux non-roux ont un mari à cheveux roux ?", hint: "Fais un tableau.", answer: "0% (toutes les rousses sont avec des roux, les roux restants épousent des non-rousses: 0 roux libre)", text_en: "Village with equal men/women. 1/3 men are redheads. Red-haired women have red-haired husbands. % non-redhead women with redhead husbands?", hint_en: "Make a table.", answer_en: "0% (all redhead women with redhead men, no redhead men left)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le nombre premier entre 90 et 100 ?", hint: "Vérifie les diviseurs.", answer: "97", text_en: "What prime number is between 90 and 100?", hint_en: "Check divisors.", answer_en: "97", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Tu lances deux dés. Quelle est la probabilité que la somme soit 7 ?", hint: "Compte les combinaisons favorables sur 36.", answer: "6/36 = 1/6 ≈ 16.7%", text_en: "Roll two dice. Probability of sum = 7?", hint_en: "Count favorable combinations out of 36.", answer_en: "6/36=1/6≈16.7%", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si a²+b²=25 et ab=12, quelle est la valeur de (a+b)² ?", hint: "(a+b)²=a²+2ab+b².", answer: "49 (25+2×12=49)", text_en: "If a²+b²=25 and ab=12, what is (a+b)²?", hint_en: "(a+b)²=a²+2ab+b².", answer_en: "49 (25+24=49)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Une pièce de monnaie a 2 faces. Si tu la lances 3 fois, quelle est la probabilité d'obtenir exactement 2 faces ?", hint: "C(3,2)×(1/2)³.", answer: "3/8 = 37.5%", text_en: "Flip a coin 3 times. Probability of exactly 2 heads?", hint_en: "C(3,2)×(1/2)³.", answer_en: "3/8=37.5%", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la valeur de log₁₀(1000) ?", hint: "10^x = 1000.", answer: "3", text_en: "What is log₁₀(1000)?", hint_en: "10^x=1000.", answer_en: "3", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu doubles la longueur du côté d'un carré, par combien multiplies-tu son aire ?", hint: "Aire = côté².", answer: "4 (côté² → (2×côté)² = 4×côté²)", text_en: "Double a square's side. By how much is area multiplied?", hint_en: "Area=side².", answer_en: "4 ((2s)²=4s²)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Résous : 3x - 7 = 2x + 5", hint: "Isole x.", answer: "x = 12", text_en: "Solve: 3x-7=2x+5", hint_en: "Isolate x.", answer_en: "x=12", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Dans un tournoi à élimination directe, 64 équipes participent. Combien de matchs y a-t-il en tout ?", hint: "Chaque match élimine une équipe.", answer: "63 matchs", text_en: "64 teams in knockout tournament. Total matches?", hint_en: "Each match eliminates one team.", answer_en: "63 matches", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la valeur de 0.999... (neuf à l'infini) ?", hint: "Pose x=0.999... et calcule 10x-x.", answer: "1 exactement (x=0.999..., 10x=9.999..., 9x=9, x=1)", text_en: "What is 0.999... (nines repeating)?", hint_en: "Let x=0.999... and compute 10x-x.", answer_en: "Exactly 1 (9x=9, x=1)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu as 100 paires de chaussettes de 10 couleurs différentes dans un tiroir sombre, combien dois-tu en tirer pour être sûr d'avoir une paire assortie ?", hint: "Dans le pire des cas...", answer: "11 chaussettes (une de chaque couleur + 1)", text_en: "100 pairs of socks, 10 colors, dark drawer. Min to pull for a matching pair?", hint_en: "Worst case...", answer_en: "11 socks (one of each color + 1)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le volume d'une sphère de rayon 3 cm ? (π≈3.14)", hint: "V = (4/3)πr³.", answer: "113.04 cm³", text_en: "Volume of sphere radius 3cm? (π≈3.14)", hint_en: "V=(4/3)πr³.", answer_en: "113.04 cm³", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "3, 8, 15, 24, 35, 48... Trouve la règle et le prochain terme.", hint: "Regarde : n²-1 ou n(n+2).", answer: "63 (n(n+2): 1×3, 2×4, 3×5, 4×6, 5×7, 6×8, 7×9=63)", text_en: "3, 8, 15, 24, 35, 48... Rule and next?", hint_en: "Look at n(n+2).", answer_en: "63 (7×9=63)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si cos(60°) = 0.5, quelle est la valeur de cos(120°) ?", hint: "120° = 180° - 60°.", answer: "-0.5 (cos(180°-x)=-cos(x))", text_en: "If cos(60°)=0.5, what is cos(120°)?", hint_en: "120°=180°-60°.", answer_en: "-0.5 (cos(180°-x)=-cos(x))", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un bateau coule. Il peut transporter 10 personnes. Il y a 25 personnes. Il peut faire 3 allers-retours. Peut-il sauver tout le monde ?", hint: "Calcule le nombre de personnes transportables.", answer: "Oui : 3 allers (30 places) - 2 retours (2 personnes reviennent) = 28 > 25", text_en: "Boat holds 10. 25 stranded. 3 round trips possible. Can all be saved?", hint_en: "Calculate total people transportable.", answer_en: "Yes: 3×10=30 spots, minus 2 returns=28>25", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si x = 2 et y = 3, quelle est la valeur de x^y + y^x ?", hint: "Calcule séparément.", answer: "2³+3²=8+9=17", text_en: "If x=2 and y=3, what is x^y + y^x?", hint_en: "Calculate separately.", answer_en: "2³+3²=8+9=17", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un canard dit 'je vois 2 canards devant moi et 2 derrière moi'. Combien y a-t-il de canards au minimum ?", hint: "Le canard au milieu peut voir 2 devant et 2 derrière.", answer: "5 canards minimum", text_en: "A duck says 'I see 2 ducks in front and 2 behind.' Minimum total ducks?", hint_en: "The middle duck sees 2 ahead and 2 behind.", answer_en: "5 ducks minimum", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Développe (a+b)³.", hint: "Multiplie (a+b)² puis × (a+b).", answer: "a³+3a²b+3ab²+b³", text_en: "Expand (a+b)³.", hint_en: "Multiply (a+b)² then by (a+b).", answer_en: "a³+3a²b+3ab²+b³", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Tu dois traverser un désert de 1000 km. Tu peux porter 600 km de carburant. Des dépôts peuvent être créés. Quel est le minimum de carburant pour traverser ?", hint: "Crée des dépôts stratégiques.", answer: "Environ 1333 km de carburant (problème classique du jeep)", text_en: "Cross 1000km desert. Carry 600km fuel. Depots allowed. Minimum fuel?", hint_en: "Create strategic depots.", answer_en: "≈1333 km of fuel (classic jeep problem)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si la probabilité qu'il pleuve est 0.3, quelle est la probabilité qu'il ne pleuve pas ?", hint: "Les probabilités complémentaires somment à 1.", answer: "0.7 (1-0.3)", text_en: "Probability of rain is 0.3. Probability of no rain?", hint_en: "Complementary probabilities sum to 1.", answer_en: "0.7 (1-0.3)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Dans une classe de 30 élèves, 18 aiment les maths, 15 aiment le français, et 10 aiment les deux. Combien n'aiment aucune des deux matières ?", hint: "Utilise le principe d'inclusion-exclusion.", answer: "7 élèves (30-(18+15-10)=7)", text_en: "30 students: 18 like math, 15 like French, 10 like both. How many like neither?", hint_en: "Inclusion-exclusion principle.", answer_en: "7 students (30-(18+15-10)=7)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la factorisation de x²-9 ?", hint: "Différence de carrés.", answer: "(x-3)(x+3)", text_en: "Factorize x²-9.", hint_en: "Difference of squares.", answer_en: "(x-3)(x+3)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un robinet remplit un réservoir en 6 heures. Une fuite le vide en 12 heures. Si les deux fonctionnent, en combien de temps se remplit-il ?", hint: "Débit net = débit entrée - débit sortie.", answer: "12 heures (1/6-1/12=1/12 par heure)", text_en: "Tap fills tank in 6h. Leak empties in 12h. Both together: fill time?", hint_en: "Net rate = fill rate - leak rate.", answer_en: "12 hours (1/6-1/12=1/12/hour)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le reste de la division de 2^100 par 3 ?", hint: "2¹=2, 2²=4≡1 (mod 3). Cycle de 2.", answer: "1 (2^100=(2²)^50≡1^50=1 mod 3)", text_en: "What is the remainder of 2^100 divided by 3?", hint_en: "2²=4≡1(mod 3). Cycle of 2.", answer_en: "1 (2^100=(2²)^50≡1 mod 3)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu places 1 grain de riz sur la case 1 d'un échiquier, 2 sur la case 2, 4 sur la case 3... combien sur la case 64 ?", hint: "C'est 2^63.", answer: "2^63 = 9 223 372 036 854 775 808 grains", text_en: "1 grain on square 1, 2 on square 2, 4 on square 3... How many on square 64?", hint_en: "It's 2^63.", answer_en: "2^63 ≈ 9.2 quintillion grains", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si 3 tailleurs cousent 3 vestes en 3 heures, combien d'heures pour 1 tailleur pour coudre 1 veste ?", hint: "1 tailleur = 1 veste en combien d'heures ?", answer: "3 heures (chaque tailleur fait 1 veste en 3h)", text_en: "3 tailors sew 3 jackets in 3 hours. 1 tailor, 1 jacket: how long?", hint_en: "1 tailor = 1 jacket in how many hours?", answer_en: "3 hours (each tailor makes 1 in 3h)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Dans un sac, il y a des billes rouges et bleues. P(rouge)=2/5. Si tu retires 1 rouge, P(rouge)=1/3. Combien de billes y avait-il ?", hint: "Pose n comme le total et résous.", answer: "10 billes (4 rouges, 6 bleues: 4/10=2/5; après: 3/9=1/3)", text_en: "Bag has red/blue marbles. P(red)=2/5. Remove 1 red: P(red)=1/3. Total?", hint_en: "Let n=total, solve.", answer_en: "10 marbles (4 red, 6 blue)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quelle est la valeur de la somme 1/2 + 1/4 + 1/8 + 1/16 + ... à l'infini ?", hint: "Série géométrique: a/(1-r).", answer: "1 (a=1/2, r=1/2: (1/2)/(1/2)=1)", text_en: "Sum of 1/2+1/4+1/8+1/16+... to infinity?", hint_en: "Geometric series: a/(1-r).", answer_en: "1 (a=1/2, r=1/2: 1)", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Un homme dépense 1/3 de son salaire en loyer, 1/4 en nourriture, 1/5 en transport. Il lui reste 260 FCFA. Quel est son salaire ?", hint: "1-(1/3+1/4+1/5)=x.", answer: "1200 FCFA (1-47/60=13/60 → 260÷(13/60)=1200)", text_en: "Man spends 1/3 on rent, 1/4 food, 1/5 transport. 260 left. Salary?", hint_en: "1-(1/3+1/4+1/5)=fraction left.", answer_en: "1200 (fraction left=13/60, 260÷13/60=1200)", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Quel est le développement de (x-y)² ?", hint: "Carrés et produit croisé.", answer: "x²-2xy+y²", text_en: "Expand (x-y)².", hint_en: "Squares and cross product.", answer_en: "x²-2xy+y²", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Si tu lis 1 page par minute, combien de temps pour lire un livre de 300 pages si tu lis 2h par jour ?", hint: "300 pages ÷ 120 pages/jour.", answer: "2.5 jours (250 min = 2j30min)", text_en: "1 page/min reading speed, 2h/day. Time to read 300-page book?", hint_en: "300 pages ÷ 120 pages/day.", answer_en: "2.5 days", category_en: "Logic" },
  { category: 'Mathématiques', difficulty: 'Difficile', text: "Si la diagonale d'un carré est 10 cm, quelle est la longueur du côté ?", hint: "Diagonale = côté × √2.", answer: "5√2 ≈ 7.07 cm", text_en: "Square diagonal is 10cm. Side length?", hint_en: "Diagonal=side×√2.", answer_en: "5√2≈7.07 cm", category_en: "Mathematics" },
  { category: 'Logique', difficulty: 'Difficile', text: "Dans une séquence 2, 4, 8, 16, 32, 64... quel est le terme n ?", hint: "C'est une puissance de 2.", answer: "2^n (terme n = 2^n)", text_en: "In sequence 2, 4, 8, 16, 32, 64... what is term n?", hint_en: "It's a power of 2.", answer_en: "2^n", category_en: "Logic" },
];

