const POOL_4 = [
  { category: 'Énigme', difficulty: 'Expert', text: "Celui qui le fabrique n'en a pas besoin. Celui qui l'achète ne s'en sert pas. Celui qui l'utilise ne le sait même pas. Qu'est-ce que c'est ?", hint: "Un objet lié à notre destinée.", answer: "Un cercueil", text_en: "Maker doesn't need it, buyer doesn't use it, user doesn't know it. What?", hint_en: "Object linked to destiny.", answer_en: "A coffin", category_en: "Riddle" },
  { category: 'Survie', difficulty: 'Expert', text: "Légère comme une plume, même la personne la plus forte du monde ne peut la retenir plus de quelques minutes. De quoi s'agit-il ?", hint: "Essentiel à la vie.", answer: "Sa respiration / le souffle", text_en: "Light as feather, strongest person can't hold for minutes. What?", hint_en: "Essential to life.", answer_en: "Their breath", category_en: "Survival" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je parle toutes les langues sans jamais avoir appris à parler. Je réponds toujours mais je n'initie jamais le dialogue. Qui suis-je ?", hint: "Je te renvoie tes propres mots.", answer: "L'écho", text_en: "Speaks all languages, never learned. Always replies, never initiates. What?", hint_en: "Sends back your own words.", answer_en: "An echo", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Plus tu m'enlèves, plus tu en laisses. Que suis-je ?", hint: "Creuse dans le sol.", answer: "Un trou", text_en: "The more you take, the more you leave behind. What am I?", hint_en: "Dig in the ground.", answer_en: "A hole", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je n'ai ni chair ni os, mais j'ai des doigts et des pouces. Que suis-je ?", hint: "Tu le portes pour avoir chaud.", answer: "Un gant", text_en: "No flesh or bone but has fingers and a thumb. What am I?", hint_en: "You wear me to keep warm.", answer_en: "A glove", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis présent dans les mers et les rivières, mais pas dans l'eau. Je suis présent dans la montagne mais pas dans la roche. Que suis-je ?", hint: "Cherche la lettre commune.", answer: "La lettre M", text_en: "In seas and rivers, not in water. In mountains not in rocks. What am I?", hint_en: "Find the common letter.", answer_en: "The letter M", category_en: "Mystery" },
  { category: 'Énigme', difficulty: 'Expert', text: "Si tu me prononces, tu me détruis. Que suis-je ?", hint: "C'est une absence.", answer: "Le silence", text_en: "Speak my name and you destroy me. What am I?", hint_en: "It's an absence.", answer_en: "Silence", category_en: "Riddle" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis au début de l'éternité, à la fin du temps et de l'espace. Je suis au début de chaque fin et à la fin de chaque commencement. Que suis-je ?", hint: "Cherche dans les mots.", answer: "La lettre E", text_en: "At start of eternity, end of time and space, start of every end, end of every beginning. What?", hint_en: "Look inside the words.", answer_en: "The letter E", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis blanc quand je suis sale. Que suis-je ?", hint: "On écrit dessus.", answer: "Un tableau noir (ou une ardoise)", text_en: "I am white when I am dirty. What am I?", hint_en: "You write on me.", answer_en: "A blackboard", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Plus je suis grande, moins je pèse. Que suis-je ?", hint: "Tu respires grâce à moi.", answer: "Un trou / une bulle d'air", text_en: "The bigger I am, the less I weigh. What am I?", hint_en: "You breathe because of me.", answer_en: "A hole / air bubble", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Tout le monde me désire mais personne ne peut me garder longtemps. Je deviens toujours du passé. Que suis-je ?", hint: "C'est précieux et fugace.", answer: "Le présent / l'instant", text_en: "Everyone wants me but no one can keep me long. I always become past. What am I?", hint_en: "Precious and fleeting.", answer_en: "The present moment", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je vis dans une maison sans portes ni fenêtres, et si je veux sortir je dois démolir. Qui suis-je ?", hint: "Tu me manges au petit déjeuner.", answer: "Un poussin dans son œuf", text_en: "I live in a house with no doors or windows. To leave I must destroy it. Who am I?", hint_en: "Eaten at breakfast.", answer_en: "A chick in its egg", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis la chose que tu cherches toujours mais que tu ne peux jamais trouver une fois que tu l'as. Que suis-je ?", hint: "Pense à une quête.", answer: "Le bonheur parfait (ou la perfection)", text_en: "You always search for me but can never find me once you have me. What am I?", hint_en: "Think of a quest.", answer_en: "Perfect happiness (or perfection)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Plus on en donne, plus on en a. Que suis-je ?", hint: "C'est quelque chose d'émotionnel.", answer: "L'amour / la gentillesse", text_en: "The more you give, the more you have. What am I?", hint_en: "It's something emotional.", answer_en: "Love / kindness", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je meurs si on m'arrose et je vis si on me laisse sécher. Que suis-je ?", hint: "Pense aux flammes.", answer: "Le feu", text_en: "I die if you water me, live if left to dry. What am I?", hint_en: "Think flames.", answer_en: "Fire", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Un homme est regardé par tout le monde mais ne peut regarder personne. Qui est-il ?", hint: "Il est au centre de l'attention mais aveugle.", answer: "Un portrait / une photo", text_en: "Watched by everyone but can watch no one. Who is he?", hint_en: "Center of attention but blind.", answer_en: "A portrait / a photo", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la chose que tu peux perdre sans que personne ne te la prenne. Que suis-je ?", hint: "C'est intérieur.", answer: "Ta dignité / ton honneur / ta foi", text_en: "I can be lost without anyone taking me. What am I?", hint_en: "It's internal.", answer_en: "Your dignity / honor / faith", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la mère de toutes les guerres et la fille de toutes les paix. Que suis-je ?", hint: "Pense à l'économie.", answer: "La pauvreté / la misère", text_en: "Mother of all wars, daughter of all peaces. What am I?", hint_en: "Think economics.", answer_en: "Poverty / misery", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Qu'est-ce qu'on voit une fois dans une vie, deux fois dans un an, quatre fois dans un mois ?", hint: "Cherche dans les mots.", answer: "La lettre I (vIe, annIversaIre... ou V en romain: vIe=1, an=deux I... — ou logiquement 'e' dans vIe/annéE)", text_en: "Seen once in a lifetime, twice in a year, four times in a month. What?", hint_en: "Look inside the words.", answer_en: "The letter 'e' (lif-e, y-e-ar has 2 e's, month... or letter pattern)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis quelque chose que tout le monde a deux fois : une fois à la naissance et une fois à la mort. Que suis-je ?", hint: "C'est une période.", answer: "Le silence / le néant", text_en: "Everyone has me twice: once at birth and once at death. What am I?", hint_en: "It's a period.", answer_en: "Silence / nothingness", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis une porte qui peut s'ouvrir de l'intérieur mais jamais de l'extérieur. Que suis-je ?", hint: "C'est dans la biologie.", answer: "La volonté / la conscience", text_en: "A door that opens from inside but never from outside. What am I?", hint_en: "It's biological.", answer_en: "The will / consciousness", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis le frère du vent, le fils de la montagne, la mère de la mer. Qui suis-je ?", hint: "Je coule.", answer: "La rivière / le fleuve", text_en: "Brother of wind, son of mountain, mother of sea. Who am I?", hint_en: "I flow.", answer_en: "A river", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis l'ennemi de la mémoire et l'ami du pardon. Que suis-je ?", hint: "Pense à l'oubli.", answer: "Le temps", text_en: "Enemy of memory, friend of forgiveness. What am I?", hint_en: "Think forgetfulness.", answer_en: "Time", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Plus tu me regardes, moins tu me vois. Que suis-je ?", hint: "C'est un phénomène optique.", answer: "L'obscurité / le noir", text_en: "The more you look, the less you see. What am I?", hint_en: "It's an optical phenomenon.", answer_en: "Darkness", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis le début de tout et la fin de rien. Que suis-je ?", hint: "Cherche dans les mots.", answer: "La lettre A (Alphabet, début de tout...)", text_en: "Beginning of everything, end of nothing. What am I?", hint_en: "Look inside words.", answer_en: "The letter A", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis l'ombre d'une montagne sans montagne, le reflet d'une eau sans eau. Que suis-je ?", hint: "C'est dans le ciel.", answer: "Un nuage / le mirage", text_en: "Shadow of a mountain without mountain, reflection of water without water. What am I?", hint_en: "It's in the sky.", answer_en: "A cloud / mirage", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis fait de bois mais je me noie si je tombe dans l'eau. Que suis-je ?", hint: "C'est petit et dangereux.", answer: "Une allumette", text_en: "Made of wood but drowns in water. What am I?", hint_en: "Small and dangerous.", answer_en: "A match", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Tout le monde me voit mais personne ne peut me toucher. Je disparais quand le soleil se couche. Que suis-je ?", hint: "Je te suis partout.", answer: "Ton ombre", text_en: "Everyone sees me but can't touch me. I disappear at sunset. What am I?", hint_en: "I follow you everywhere.", answer_en: "Your shadow", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis le seul luxe qui ne coûte rien mais que peu de gens possèdent. Que suis-je ?", hint: "C'est une vertu rare.", answer: "La sagesse / la paix intérieure", text_en: "The only luxury that costs nothing but few possess. What am I?", hint_en: "It's a rare virtue.", answer_en: "Wisdom / inner peace", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la chose qui se perd quand on la garde et qu'on garde quand on la perd. Que suis-je ?", hint: "Pense à la vie.", answer: "Sa vie (on perd sa vie en la gardant trop précieusement)", text_en: "Lost when kept, kept when lost. What am I?", hint_en: "Think about life.", answer_en: "One's life (lost by keeping it, kept by giving it)", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis le livre que tout le monde lit mais que personne n'a écrit. Que suis-je ?", hint: "Regarde autour de toi.", answer: "Le monde / la nature", text_en: "The book everyone reads but no one wrote. What am I?", hint_en: "Look around you.", answer_en: "The world / nature", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je grandis quand tu me nourris de peur, mais je meurs quand tu m'affrontes. Que suis-je ?", hint: "C'est un obstacle mental.", answer: "La peur elle-même / l'anxiété", text_en: "I grow when fed by fear, die when confronted. What am I?", hint_en: "It's a mental obstacle.", answer_en: "Fear itself / anxiety", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Un homme a 2 fils et chaque fils a une sœur. Combien d'enfants a-t-il ?", hint: "Peut-on avoir une seule sœur commune ?", answer: "3 enfants (2 fils + 1 sœur)", text_en: "A man has 2 sons, each has a sister. How many children?", hint_en: "Can they share one sister?", answer_en: "3 children (2 sons + 1 sister)", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Il y a quelque chose que tu fais seul, que tu ne peux pas faire faire par quelqu'un d'autre, même si tu paies. Quoi ?", hint: "C'est une expérience intime.", answer: "Mourir / rêver / souffrir / aimer vraiment", text_en: "Something you do alone that no one can do for you, even paid. What?", hint_en: "An intimate experience.", answer_en: "Die / dream / suffer / truly love", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la chose que tu cherches toute ta vie mais qui était là depuis le début. Que suis-je ?", hint: "C'est intérieur.", answer: "Toi-même / la connaissance de soi", text_en: "Searched for a lifetime but there since the beginning. What am I?", hint_en: "It's internal.", answer_en: "Yourself / self-knowledge", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la chose la plus légère du monde mais personne ne peut me tenir plus d'une minute. Que suis-je ?", hint: "Essentiel pour vivre.", answer: "Sa respiration", text_en: "Lightest thing in the world but no one holds me more than a minute. What am I?", hint_en: "Essential to live.", answer_en: "Your breath", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis noir de nuit, rouge le jour et vert en été. Que suis-je ?", hint: "C'est dans la nature.", answer: "Un arbre (silhouette noire la nuit, rouge à l'automne, vert en été)", text_en: "Black at night, red by day, green in summer. What am I?", hint_en: "It's in nature.", answer_en: "A tree (silhouette black at night, red in fall, green in summer)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis le paradoxe vivant : plus tu me partages, plus tu as de moi. Que suis-je ?", hint: "C'est émotionnel.", answer: "La joie / le bonheur / le savoir", text_en: "Living paradox: more you share, more you have. What am I?", hint_en: "It's emotional.", answer_en: "Joy / happiness / knowledge", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis une prison sans murs ni barreaux. Pourtant les plus grands hommes y sont enfermés. Que suis-je ?", hint: "C'est dans la tête.", answer: "L'ignorance / le préjugé / les croyances limitantes", text_en: "A prison with no walls or bars, yet great men are locked inside. What am I?", hint_en: "It's in the mind.", answer_en: "Ignorance / prejudice / limiting beliefs", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis là avant toi, je serai là après toi, mais entre les deux je vis à travers toi. Que suis-je ?", hint: "C'est universel.", answer: "Le temps", text_en: "Here before you, after you, but live through you in between. What am I?", hint_en: "It's universal.", answer_en: "Time", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Ce que j'ai de plus grand rapetisse ce que j'ai de plus petit. Que suis-je ?", hint: "Pense aux nombres.", answer: "La fraction (plus le dénominateur est grand, plus la fraction est petite)", text_en: "The bigger my greatest part, the smaller my smallest. What am I?", hint_en: "Think numbers.", answer_en: "A fraction (bigger denominator = smaller fraction)", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis le mot que tout le monde dit souvent mais que personne n'a jamais vu. Que suis-je ?", hint: "C'est dans l'air.", answer: "Le mot 'vent' (ou 'demain')", text_en: "The word everyone says often but no one has ever seen. What am I?", hint_en: "It's in the air.", answer_en: "The word 'wind' (or 'tomorrow')", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je te vois sans yeux et je t'entends sans oreilles. Je n'ai pas de cerveau mais je pense à tout. Que suis-je ?", hint: "Tu me consultes.", answer: "Un miroir (ou une conscience)", text_en: "I see without eyes, hear without ears. No brain but think of everything. What am I?", hint_en: "You consult me.", answer_en: "A mirror (or a conscience)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la chose qu'on cherche dans le futur, qu'on trouve dans le présent et qu'on perd dans le passé. Que suis-je ?", hint: "C'est une quête universelle.", answer: "La vérité / la sagesse / le sens de la vie", text_en: "Sought in the future, found in the present, lost in the past. What am I?", hint_en: "A universal quest.", answer_en: "Truth / wisdom / meaning of life", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la seule chose qu'on puisse couper sans couteau, brûler sans feu et construire sans matériaux. Que suis-je ?", hint: "C'est immatériel.", answer: "Un rêve / une relation / l'espoir", text_en: "Only thing cut without knife, burned without fire, built without materials. What?", hint_en: "It's immaterial.", answer_en: "A dream / a relationship / hope", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Plus tu avances vers moi, plus je m'éloigne. Mais si tu t'arrêtes de me chercher, je viens à toi. Que suis-je ?", hint: "Pense au bonheur.", answer: "Le bonheur / la sérénité", text_en: "The closer you get to me, the further I move. But stop searching and I come to you. What am I?", hint_en: "Think happiness.", answer_en: "Happiness / serenity", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis ce qui reste quand on a tout perdu. Que suis-je ?", hint: "C'est une force intérieure.", answer: "L'espoir / la volonté / le caractère", text_en: "What remains when everything is lost. What am I?", hint_en: "It's an inner strength.", answer_en: "Hope / will / character", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la maison du roi mais personne ne peut y habiter. Que suis-je ?", hint: "C'est dans un jeu.", answer: "Un château aux échecs", text_en: "House of the king but no one can live in me. What am I?", hint_en: "It's in a game.", answer_en: "A chess castle (rook)", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je me souviens de tout mais j'oublie tout aussi. Plus je vieillis, plus je grandis, mais un jour je disparais. Que suis-je ?", hint: "Pense à quelque chose qui grandit et fond.", answer: "Un glacier / la neige", text_en: "I remember all but forget all. Older I get, bigger I grow, then one day gone. What am I?", hint_en: "Think of something that grows and melts.", answer_en: "A glacier / snow", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis quelque chose que tu fais chaque nuit, que tu ne contrôles pas, et dont tu te souviens rarement. Que suis-je ?", hint: "C'est dans le sommeil.", answer: "Un rêve", text_en: "Done every night, uncontrolled, rarely remembered. What am I?", hint_en: "It's during sleep.", answer_en: "A dream", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la frontière entre deux mondes. Je n'appartiens ni à l'un ni à l'autre. Que suis-je ?", hint: "Pense aux limites.", answer: "L'horizon / le seuil / la ligne d'équilibre", text_en: "Border between two worlds, belonging to neither. What am I?", hint_en: "Think boundaries.", answer_en: "The horizon / a threshold / a dividing line", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis ce que les riches veulent, ce que les pauvres ont, et ce que les sages refusent. Que suis-je ?", hint: "Pense au superflu.", answer: "Rien (les riches veulent plus de rien à désirer, les pauvres ont rien, les sages refusent le superflu)", text_en: "What the rich want, the poor have, and the wise refuse. What am I?", hint_en: "Think of excess.", answer_en: "Nothing (rich want nothing more, poor have nothing, wise refuse excess)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la chose que chacun a en double mais qu'on ne peut jamais utiliser en même temps. Que suis-je ?", hint: "C'est sur le visage.", answer: "Les yeux", text_en: "Everyone has me in duplicate but can never use both at once. What am I?", hint_en: "It's on the face.", answer_en: "Eyes (we see as one but have two)", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis le seul être qui marche sur 4 pattes, puis 2, puis 3. Qui suis-je ?", hint: "L'énigme du sphinx.", answer: "L'homme", text_en: "The only being that walks on 4, then 2, then 3 legs. Who am I?", hint_en: "The sphinx's riddle.", answer_en: "Man (crawls, walks, uses cane)", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis un mot que tout le monde prononce mal. Que suis-je ?", hint: "Réfléchis à la question elle-même.", answer: "Le mot 'mal' (tout le monde prononce 'mal' correctement quand il dit 'prononce mal')", text_en: "I'm a word everyone mispronounces. What am I?", hint_en: "Think about the question itself.", answer_en: "'Wrong' — everyone pronounces 'wrong' correctly", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis l'ennemi de la liberté mais l'ami de la sécurité. Que suis-je ?", hint: "Pense aux systèmes sociaux.", answer: "La loi / la règle / la contrainte", text_en: "Enemy of freedom but friend of safety. What am I?", hint_en: "Think social systems.", answer_en: "Law / rule / constraint", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis le fils de l'eau mais si l'eau me touche, je meurs. Qui suis-je ?", hint: "Pense aux phénomènes naturels.", answer: "La glace", text_en: "Son of water but water kills me. Who am I?", hint_en: "Think natural phenomena.", answer_en: "Ice", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis toujours devant les yeux mais jamais vu. Je suis derrière le cœur mais jamais ressenti directement. Que suis-je ?", hint: "C'est une vérité profonde.", answer: "L'âme / la conscience", text_en: "Always before the eyes but never seen. Behind the heart but never felt directly. What am I?", hint_en: "A deep truth.", answer_en: "The soul / consciousness", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la seule chose qui puisse être donnée et qui revient automatiquement. Que suis-je ?", hint: "Pense aux émotions contagieuses.", answer: "Le sourire / la gentillesse", text_en: "The only thing given that automatically comes back. What am I?", hint_en: "Think contagious emotions.", answer_en: "A smile / kindness", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Une femme a 5 enfants. La moitié sont des garçons. Comment est-ce possible ?", hint: "'La moitié' n'est pas nécessairement 2,5.", answer: "Tous les 5 sont des garçons (ils sont tous la moitié garçons/filles si tu comptes différemment — ou : la femme ment)", text_en: "A woman has 5 children. Half are boys. How?", hint_en: "'Half' doesn't have to mean 2.5.", answer_en: "All 5 are boys — they are all half of the human race", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Qu'est-ce que plus ça grandit, moins ça pèse ?", hint: "C'est dans le ciel.", answer: "Un trou / une bulle / un ballon", text_en: "The bigger it grows, the less it weighs. What is it?", hint_en: "It's in the sky.", answer_en: "A hole / bubble / balloon", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis ce qu'on cherche dans les autres et qu'on trouve en soi. Que suis-je ?", hint: "C'est une qualité.", answer: "La force / la paix / l'amour", text_en: "Sought in others, found within. What am I?", hint_en: "It's a quality.", answer_en: "Strength / peace / love", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je peux remplir une pièce sans occuper d'espace. Que suis-je ?", hint: "C'est sensoriel.", answer: "La lumière / le son / la chaleur", text_en: "I can fill a room without taking any space. What am I?", hint_en: "It's sensory.", answer_en: "Light / sound / heat", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je pèse autant vide que plein. Que suis-je ?", hint: "C'est un objet creux.", answer: "Un ballon (gonflé à l'air — même masse, poids légèrement différent)", text_en: "Same weight empty as full. What am I?", hint_en: "It's hollow.", answer_en: "A balloon (air has negligible mass)", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis la chose que tu peux posséder sans jamais la voir. Je ne suis pas matérielle mais je vaut plus que l'or. Que suis-je ?", hint: "C'est moral.", answer: "L'honneur / la réputation / la dignité", text_en: "Can be possessed but never seen. Not material but worth more than gold. What am I?", hint_en: "It's moral.", answer_en: "Honor / reputation / dignity", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis blanc et pur, noir et impur, rouge et mortel. Que suis-je à chaque fois ?", hint: "Pense à des substances différentes.", answer: "Blanc=neige/sel, Noir=charbon/pétrole, Rouge=sang/feu", text_en: "White and pure, black and impure, red and deadly. What am I each time?", hint_en: "Think different substances.", answer_en: "White=snow/salt, Black=coal/oil, Red=blood/fire", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis le langage que tout le monde comprend mais que personne n'a appris. Que suis-je ?", hint: "Pense aux expressions universelles.", answer: "Les émotions / la musique / le sourire", text_en: "The language everyone understands but no one learned. What am I?", hint_en: "Think universal expressions.", answer_en: "Emotions / music / a smile", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis une porte que tu ouvres de l'intérieur et que l'on ne peut fermer de l'extérieur. Que suis-je ?", hint: "C'est dans l'esprit.", answer: "L'esprit / l'imagination / le cœur", text_en: "A door opened from inside that can't be closed from outside. What am I?", hint_en: "It's in the mind.", answer_en: "The mind / imagination / the heart", category_en: "Philosophy" },
  { category: 'Énigme', difficulty: 'Expert', text: "Je suis la fin de tout commencement et le commencement de toute fin. Je suis présent dans chaque fin de ligne. Que suis-je ?", hint: "Regarde les mots.", answer: "La lettre N", text_en: "End of every beginning, beginning of every end, present at end of every line. What am I?", hint_en: "Look at the words.", answer_en: "The letter N", category_en: "Riddle" },
  { category: 'Mystère', difficulty: 'Expert', text: "Je suis ce que le temps efface mais que la mémoire garde. Que suis-je ?", hint: "C'est précieux.", answer: "Un souvenir / une cicatrice / une leçon", text_en: "What time erases but memory keeps. What am I?", hint_en: "It's precious.", answer_en: "A memory / scar / lesson", category_en: "Mystery" },
  { category: 'Philosophie', difficulty: 'Expert', text: "Je suis fait de rien mais je peux tout porter. Que suis-je ?", hint: "Pense à l'esprit.", answer: "Une idée / la foi / la confiance", text_en: "Made of nothing but can carry everything. What am I?", hint_en: "Think of the mind.", answer_en: "An idea / faith / trust", category_en: "Philosophy" },
];

