// ─────────────────────────────────────────────
//  Algorithme de sélection — 365 jours sans répétition
//  Chaque pool a 75 questions.
//  Jour D (1-based depuis le 1er janvier de l'année en cours)
//  On utilise: index = (D - 1 + offset_pool) % pool.length
//  offsets différents par pool pour éviter les corrélations
// ─────────────────────────────────────────────
export const getQuestionsForToday = () => {
  const now = new Date();
  const formatter = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Africa/Douala',
    year: 'numeric', month: '2-digit', day: '2-digit'
  });
  const [day, month, year] = formatter.format(now).split('/').map(Number);

  // Jour de l'année (1 à 365/366)
  const startOfYear = new Date(Date.UTC(year, 0, 1));
  const nowUTC = new Date(Date.UTC(year, month - 1, day));
  const dayOfYear = Math.floor((nowUTC - startOfYear) / 86400000) + 1;

  // Offsets uniques par pool pour briser les corrélations
  const OFFSETS = [0, 17, 34, 51, 68];

  const pools = [POOL_1, POOL_2, POOL_3, POOL_4, POOL_5];
  const timeSlots = [
    { start: 8, end: 10, points: 1 },
    { start: 10, end: 12, points: 2 },
    { start: 12, end: 14, points: 4 },
    { start: 14, end: 16, points: 7 },
    { start: 16, end: 18, points: 15 },
  ];

  return pools.map((pool, i) => {
    const idx = (dayOfYear - 1 + OFFSETS[i]) % pool.length;
    return {
      ...pool[idx],
      id: i + 1,
      start: timeSlots[i].start,
      end: timeSlots[i].end,
      points: timeSlots[i].points,
    };
  });
};

export const QUESTIONS_DU_JOUR = getQuestionsForToday();

export const getCurrentHour = () => {
  const formatter = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Africa/Douala',
    hour: '2-digit',
    hour12: false,
  });
  return parseInt(formatter.format(new Date()), 10);
};

export const getLocalizedQuestionData = (question) => {
  if (!question) return null;
  const isEn = LANG === 'en';
  return {
    ...question,
    displayCategory: isEn && question.category_en ? question.category_en : question.category,
    displayText: isEn && question.text_en ? question.text_en : question.text,
    displayHint: isEn && question.hint_en ? question.hint_en : question.hint,
    displayAnswer: isEn && question.answer_en ? question.answer_en : question.answer,
  };
};